from typing import Union


def _validate_positive_number(value: Union[int, float], name: str) -> None:
    if isinstance(value, bool) or not isinstance(value, (int, float)):
        raise TypeError(f"{name} must be an int or float, got {type(value).__name__}")
    if value <= 0:
        raise ValueError(f"{name} must be strictly greater than zero, got {value}")


