from .shapes import Circle, Rectangle
from .validation import _validate_positive_number


class Cylinder:
    def __init__(self, base_shape: Circle, height: float):
        if not isinstance(base_shape, Circle):
            raise TypeError(
                f"base_shape must be a Circle, got {type(base_shape).__name__}"
            )
        _validate_positive_number(height, "height")
        self.base_shape = base_shape
        self.height = height

    def volume(self) -> float:
        return self.base_shape.area() * self.height


class Cuboid:
    def __init__(self, base_shape: Rectangle, height: float):
        if not isinstance(base_shape, Rectangle):
            raise TypeError(
                f"base_shape must be a Rectangle, got {type(base_shape).__name__}"
            )
        _validate_positive_number(height, "height")
        self.base_shape = base_shape
        self.height = height

    def volume(self) -> float:
        return self.base_shape.area() * self.height
